CREATE OR REPLACE FUNCTION fpa_tel_memno_loan_all (as_memno char,adt_date timestamp(0)) RETURNS bigint AS $body$
DECLARE

  ldc_balance bigint;

BEGIN
  select sum(pka_com_function.fp_lon_get_balance_atdate(loan_contract_no , adt_date ))
  into STRICT   ldc_balance
  from   sc_lon_m_loan_card
  where ( membership_no = as_memno);
  return coalesce(ldc_balance,0);
exception when others then CALL spa_dberror('FPA_TEL_MEMNO_LOAN_ALL');return null;
END;
$body$
